package com.chaobo.scm.supplier.infrastructure.persistence.profile;import org.apache.ibatis.annotations.*;
@Mapper public interface SupplierAdmissionMapper{record Row(long id,String no,String code,String name,String taxNo,String type,String contact,String mobile,String settlement,int status,String reject,int version){}@Select("SELECT admission_id id,admission_no no,candidate_supplier_code code,candidate_supplier_name name,tax_no taxNo,supplier_type type,contact_name contact,contact_mobile mobile,settlement_json settlement,admission_status status,reject_reason reject,version FROM sup_supplier_admission WHERE admission_id=#{id} AND deleted=0")Row find(long id);@Insert("INSERT INTO sup_supplier_admission(admission_id,admission_no,candidate_supplier_code,candidate_supplier_name,tax_no,supplier_type,admission_status,contact_name,contact_mobile,settlement_json,reject_reason,created_by,updated_by,version,deleted) VALUES(#{r.id},#{r.no},#{r.code},#{r.name},#{r.taxNo},#{r.type},#{r.status},#{r.contact},#{r.mobile},CAST(#{r.settlement} AS JSON),#{r.reject},#{op},#{op},#{r.version},0)")void insert(@Param("r")Row r,@Param("op")long op);@Update("UPDATE sup_supplier_admission SET admission_status=#{r.status},reject_reason=#{r.reject},updated_by=#{op},version=#{r.version} WHERE admission_id=#{r.id} AND version=#{expected} AND deleted=0")int update(@Param("r")Row r,@Param("expected")int expected,@Param("op")long op);}
